#include <numeric>
#include <iostream>
#include <vector>
#include <stack>
using namespace std;

struct TreeNode {
    int val;
    TreeNode *left;
    TreeNode *right;
    TreeNode(int x) : val(x), left(NULL), right(NULL) {}
};

class Solution {
public:
    vector<int> postorderTraversal(TreeNode* root) {
        if (!root) return {};
        stack<TreeNode*> stack1, stack2;
        stack1.push(root);
        while (!stack1.empty()) {
            TreeNode* node = stack1.top();
            stack1.pop();
            stack2.push(node);
            if (node->left) stack1.push(node->left);
            if (node->right) stack1.push(node->right);
        }
        vector<int> res;
        while (!stack2.empty()) {
            res.push_back(stack2.top()->val);
            stack2.pop();
        }
        return res;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    cin >> n;
    vector<int> nodes(n * 3);
    for (int i = 0; i < n * 3; i++) cin >> nodes[i];
    TreeNode* root = new TreeNode(nodes[0]);
    stack<TreeNode*> stack;
    stack.push(root);
    int i = 1;
    while (!stack.empty() && i < n * 3) {
        TreeNode* node = stack.top();
        if (nodes[i] != -1) {
            node->left = new TreeNode(nodes[i]);
            stack.push(node->left);
        }
        i++;
        if (i < n * 3 && nodes[i] != -1) {
            node->right = new TreeNode(nodes[i]);
            stack.push(node->right);
        }
        i++;
        stack.pop();
    }
    Solution sol;
    vector<int> ans = sol.postorderTraversal(root);
    for (int num : ans) cout << num << '\n';
    return 0;
}
